import type { FlashcardDeck } from './flashcard-data';

export const setTextFlashcardDecks: FlashcardDeck[] = [
  // ─────────────────────────────────────────────
  // AN INSPECTOR CALLS — COMPREHENSIVE (40 cards)
  // ─────────────────────────────────────────────
  {
    id: 'aic-comprehensive',
    title: 'An Inspector Calls — Comprehensive',
    description: '40 exam-ready cards covering quotes, characters, themes, and context for An Inspector Calls',
    category: 'Set Texts',
    board: 'AQA',
    cards: [
      // ── QUOTE CARDS (15) ──
      { id: 'aic-q1', front: '"We are members of one body. We are responsible for each other."', back: 'Speaker: Inspector Goole (Act 3)\n\nMeaning: The Inspector delivers his final message — society is interconnected and everyone has a duty of care.\n\nTechniques: Repetition of "we," declarative sentences, biblical/socialist rhetoric, inclusive pronoun.\n\nThemes: Collective responsibility, socialism, morality.\n\nExam point: This is Priestley\'s mouthpiece moment — the Inspector voices the play\'s central thesis. The repetition of "we" forces the Birlings (and the audience) to accept they cannot opt out of social responsibility. Written in 1945, Priestley urges post-war Britain to build a fairer society and not repeat the selfish capitalism of 1912.' },
      { id: 'aic-q2', front: '"If we don\'t learn that lesson, then we\'ll be taught it in fire and blood and anguish."', back: 'Speaker: Inspector Goole (Act 3)\n\nMeaning: If society ignores its responsibility, the consequences will be catastrophic.\n\nTechniques: Tricolon ("fire and blood and anguish"), prophetic tone, conditional threat, polysyndeton.\n\nThemes: Collective responsibility, consequences, war.\n\nExam point: The 1912 audience would not yet know World War I was coming — but Priestley\'s 1945 audience had already lived through two wars. The Inspector\'s prophecy has already come true, giving his words devastating dramatic irony. Priestley warns that a third catastrophe awaits if post-war society repeats pre-war selfishness.' },
      { id: 'aic-q3', front: '"But these girls aren\'t cheap labour — they\'re people."', back: 'Speaker: Sheila Birling (Act 1)\n\nMeaning: Sheila challenges her father\'s view that workers are merely economic units.\n\nTechniques: Antithesis ("cheap labour" vs "people"), dash creates dramatic pause, declarative.\n\nThemes: Class, exploitation, empathy, generational change.\n\nExam point: Sheila\'s awakening begins here — she recognises Eva Smith\'s humanity where her father only sees profit margins. Priestley uses Sheila to represent the younger generation\'s capacity for moral growth, contrasting her with Birling\'s capitalist dehumanisation of workers.' },
      { id: 'aic-q4', front: '"The way some of these cranks talk and write now, you\'d think everybody has to look after everybody else."', back: 'Speaker: Arthur Birling (Act 1)\n\nMeaning: Birling dismisses socialist ideas as foolish and extreme.\n\nTechniques: Dismissive noun "cranks," hyperbole, dramatic irony (the Inspector will prove him wrong).\n\nThemes: Capitalism vs socialism, arrogance, class.\n\nExam point: Priestley sets Birling up as a dramatic straw man — his dismissal of collective responsibility is immediately undermined by the Inspector\'s arrival. The audience knows Birling is wrong, making his confidence absurd. This establishes him as the embodiment of the selfish capitalist attitude Priestley wants to dismantle.' },
      { id: 'aic-q5', front: '"I\'m ashamed of you as well — yes both of you."', back: 'Speaker: Sheila Birling (Act 3)\n\nMeaning: Sheila turns on her parents, expressing moral disgust at their refusal to accept blame.\n\nTechniques: Repetition, dash for emphasis, inclusive condemnation, emotive language ("ashamed").\n\nThemes: Generational divide, morality, responsibility.\n\nExam point: The parent-child hierarchy inverts — Sheila now judges her parents rather than obeying them. Priestley uses this reversal to suggest that moral authority comes from conscience, not age or status. The younger generation must lead the change that the older generation refuses.' },
      { id: 'aic-q6', front: '"You\'re squiffy."', back: 'Speaker: Sheila to Eric (Act 1)\n\nMeaning: Sheila notices Eric has been drinking — a seemingly throwaway comment that foreshadows darker revelations.\n\nTechniques: Colloquial language, foreshadowing, dramatic irony.\n\nThemes: Appearance vs reality, secrets, the Birling family facade.\n\nExam point: Priestley plants early clues that the Birling family is not as respectable as it appears. Eric\'s alcoholism — hidden behind closed doors — symbolises the moral rot beneath the family\'s polished surface. This moment also shows Sheila\'s perceptiveness, foreshadowing her role as the family\'s moral conscience.' },
      { id: 'aic-q7', front: '"I was in that state where a chap easily turns nasty."', back: 'Speaker: Eric Birling (Act 3)\n\nMeaning: Eric confesses to forcing himself on Eva Smith while drunk.\n\nTechniques: Euphemism ("that state," "turns nasty"), passive phrasing to deflect blame, understatement.\n\nThemes: Gender, power, class, toxic masculinity, exploitation.\n\nExam point: Eric\'s euphemistic language reveals how upper-class men minimised violence against working-class women. "Turns nasty" avoids naming the assault directly, reflecting a society that enabled such behaviour by refusing to name it. Priestley exposes how class privilege gave men like Eric impunity.' },
      { id: 'aic-q8', front: '"She was claiming elaborate fine feelings and scruples that were simply absurd in a girl in her position."', back: 'Speaker: Mrs Birling (Act 2)\n\nMeaning: Mrs Birling claims Eva Smith had no right to feelings of pride or morality because of her class.\n\nTechniques: Dismissive adjectives ("elaborate," "absurd"), snobbery encoded in "a girl in her position."\n\nThemes: Class prejudice, dehumanisation, hypocrisy.\n\nExam point: Mrs Birling denies working-class women the right to have feelings — she literally cannot believe a poor girl would have moral principles. Priestley exposes the dehumanising logic of class hierarchy: the rich assume the poor are morally and emotionally inferior, which justifies their exploitation.' },
      { id: 'aic-q9', front: '"Unsinkable, absolutely unsinkable."', back: 'Speaker: Arthur Birling (Act 1), referring to the Titanic\n\nMeaning: Birling confidently predicts the Titanic will never sink — just before its maiden voyage.\n\nTechniques: Dramatic irony, repetition for emphasis, declarative certainty.\n\nThemes: Arrogance, foolishness, hubris.\n\nExam point: The 1945 audience knows the Titanic sank in 1912 — so Birling is immediately exposed as a fool. Priestley systematically destroys Birling\'s credibility so that when he dismisses socialism, the audience knows to reject his views. Every confident prediction Birling makes is wrong, undermining capitalist certainty.' },
      { id: 'aic-q10', front: '"I don\'t come into this suicide business."', back: 'Speaker: Mrs Birling (Act 2)\n\nMeaning: Mrs Birling refuses to accept any connection between her actions and Eva\'s death.\n\nTechniques: Dismissive noun "business," first person denial, dramatic irony.\n\nThemes: Denial, responsibility, class.\n\nExam point: The word "business" reduces Eva\'s death to an inconvenience — something Mrs Birling can distance herself from. Priestley shows that the upper classes protect themselves through wilful ignorance. Her denial becomes increasingly absurd as the Inspector reveals her direct involvement.' },
      { id: 'aic-q11', front: '"Public men, Mr Birling, have responsibilities as well as privileges."', back: 'Speaker: Inspector Goole (Act 1)\n\nMeaning: The Inspector reminds Birling that power comes with duty, not just entitlement.\n\nTechniques: Antithesis ("responsibilities" vs "privileges"), formal address, declarative.\n\nThemes: Responsibility, power, class.\n\nExam point: This directly challenges Birling\'s worldview that wealth entitles him to do as he pleases. Priestley connects this to the post-war welfare state debate — those with power and wealth must use them for the public good, not just personal gain.' },
      { id: 'aic-q12', front: '"Girls of that class—"', back: 'Speaker: Mrs Birling (Act 2)\n\nMeaning: Mrs Birling begins to categorise Eva by class before being cut off.\n\nTechniques: Interrupted speech (dash), casual classism, dehumanising generalisation.\n\nThemes: Class prejudice, dehumanisation, social hierarchy.\n\nExam point: The dash is significant — either she is interrupted or cannot finish the thought. Either way, "that class" reduces Eva to a category rather than a person. Priestley shows how class language itself is a tool of oppression, allowing the rich to dismiss entire groups without engaging with individuals.' },
      { id: 'aic-q13', front: '"You\'re not the kind of father a chap could go to when he\'s in trouble."', back: 'Speaker: Eric Birling (Act 3)\n\nMeaning: Eric reveals the emotional distance between himself and his father.\n\nTechniques: Second person accusation, colloquial "chap," honest tone contrasting Birling\'s pomposity.\n\nThemes: Family, failed fatherhood, generational conflict.\n\nExam point: Eric\'s accusation exposes the Birling family as emotionally hollow beneath its respectability. Birling prioritises reputation over his children\'s wellbeing. Priestley suggests that capitalist values — profit, status, appearances — corrupt even the most intimate family relationships.' },
      { id: 'aic-q14', front: '"A man has to make his own way — has to look after himself."', back: 'Speaker: Arthur Birling (Act 1)\n\nMeaning: Birling delivers his philosophy of individual self-interest.\n\nTechniques: Repetition of "has to," declarative, dashes for emphasis, individualist manifesto.\n\nThemes: Capitalism, individualism vs collectivism, selfishness.\n\nExam point: This is the thesis the entire play exists to demolish. Birling\'s philosophy of self-reliance sounds reasonable until Priestley shows its real-world consequences: Eva Smith dies because everyone looked after themselves instead of each other. The Inspector\'s final speech is the direct antithesis of this moment.' },
      { id: 'aic-q15', front: '"Between us we drove that girl to commit suicide."', back: 'Speaker: Sheila Birling (Act 3)\n\nMeaning: Sheila accepts collective guilt — the family as a whole is responsible.\n\nTechniques: Inclusive pronoun "we," emotive verb "drove," declarative acceptance.\n\nThemes: Collective responsibility, guilt, moral growth.\n\nExam point: Sheila has fully absorbed the Inspector\'s lesson — she uses "we" rather than blaming individuals, recognising that Eva\'s death resulted from a chain of selfish actions. Priestley rewards Sheila\'s empathy by making her the moral centre of the play, showing the audience what genuine responsibility looks like.' },

      // ── CHARACTER CARDS (10) ──
      { id: 'aic-c1', front: 'Arthur Birling — Character Profile', back: 'Role: Wealthy factory owner, patriarch of the Birling family, represents the capitalist establishment.\n\nKey traits: Arrogant, pompous, self-interested, socially ambitious (married above his class), dismissive of responsibility.\n\nKey actions: Sacked Eva Smith for requesting a pay rise; refuses to learn from the Inspector\'s visit.\n\nPriestley\'s purpose: Birling is a dramatic vehicle for discrediting capitalism. His wrong predictions (Titanic, "no war") destroy his credibility so the audience rejects his ideology. He embodies the selfish individualism Priestley opposes.\n\nExam tip: Always link Birling to Priestley\'s political message — he is not just a character but a symbol of everything wrong with pre-war capitalism.' },
      { id: 'aic-c2', front: 'Sheila Birling — Character Profile', back: 'Role: Birling\'s daughter, engaged to Gerald Croft, represents the younger generation\'s capacity for change.\n\nKey traits: Initially naive and materialistic; becomes empathetic, morally aware, and outspoken.\n\nKey actions: Got Eva sacked from Milwards out of jealousy; accepts full responsibility and challenges her parents.\n\nPriestley\'s purpose: Sheila\'s transformation is the play\'s moral arc — she proves people CAN change if they listen to their conscience. She becomes the Inspector\'s ally, continuing his work after he leaves.\n\nExam tip: Track her journey from spoiled girl to moral authority — Priestley uses her growth to show the audience what they should aspire to.' },
      { id: 'aic-c3', front: 'Mrs Sybil Birling — Character Profile', back: 'Role: Arthur\'s wife, head of the Brumley Women\'s Charity Organisation, represents upper-class hypocrisy.\n\nKey traits: Cold, snobbish, prejudiced, in denial, refuses to accept responsibility.\n\nKey actions: Rejected Eva\'s plea for help at the charity; blamed the father of Eva\'s child (unknowingly her own son Eric).\n\nPriestley\'s purpose: Mrs Birling embodies the cruelty of class prejudice disguised as respectability. Her charity work is performative — she helps only those she deems "deserving." She represents the older generation\'s refusal to change.\n\nExam tip: Emphasise the irony of her running a charity while denying help to the most vulnerable. Her dramatic irony (blaming her own son) is devastating.' },
      { id: 'aic-c4', front: 'Eric Birling — Character Profile', back: 'Role: Birling\'s son, represents the consequences of privilege without responsibility.\n\nKey traits: Alcoholic, immature, capable of violence, but ultimately shows genuine remorse.\n\nKey actions: Forced himself on Eva while drunk; stole money from his father\'s business to support her; accepts guilt.\n\nPriestley\'s purpose: Eric shows how upper-class privilege enables exploitation — his wealth and status gave him access and impunity. Like Sheila, he accepts responsibility, proving the younger generation can learn.\n\nExam tip: Eric is both perpetrator and product — his behaviour is enabled by a class system that never taught him consequences. He represents the capacity for change alongside genuine harm.' },
      { id: 'aic-c5', front: 'Inspector Goole — Character Profile', back: 'Role: The Inspector, a mysterious figure who may be supernatural, functions as Priestley\'s moral mouthpiece.\n\nKey traits: Authoritative, moral, relentless, classless (cannot be placed socially), prophetic.\n\nKey actions: Systematically interrogates each Birling; delivers the final moral speech; disappears mysteriously.\n\nPriestley\'s purpose: The Inspector is not a realistic character — he is a dramatic device. His name "Goole" suggests "ghoul" (ghost). He may represent conscience, God, time, or socialist morality. He exists to shatter the Birlings\' complacency.\n\nExam tip: Do not get sidetracked debating whether he is "real" — focus on his FUNCTION as Priestley\'s tool for forcing both the Birlings and the audience to confront their responsibility.' },
      { id: 'aic-c6', front: 'Gerald Croft — Character Profile', back: 'Role: Sheila\'s fiance, son of a rival industrialist, represents the aristocratic upper class.\n\nKey traits: Charming, socially confident, morally ambiguous — genuinely cared for Daisy Renton but ultimately abandoned her.\n\nKey actions: Had an affair with Eva/Daisy; provided her with money and lodging; later helps discredit the Inspector.\n\nPriestley\'s purpose: Gerald is the most morally complex character — he showed genuine kindness but ultimately treated Eva as disposable. After the Inspector leaves, he joins the older generation in denial, showing that social class loyalty overrides moral awakening.\n\nExam tip: Gerald\'s position between genuine feeling and class loyalty makes him ideal for nuanced analysis — he is neither villain nor hero.' },
      { id: 'aic-c7', front: 'Eva Smith / Daisy Renton — Character Profile', back: 'Role: The unseen victim, a working-class woman exploited by every member of the Birling family.\n\nKey traits: Never appears on stage; described as pretty, spirited, principled, and ultimately desperate.\n\nKey actions: Led a strike, worked at Milwards, had affairs with Gerald and Eric, applied to Mrs Birling\'s charity, committed suicide.\n\nPriestley\'s purpose: Eva represents every working-class person exploited by the class system. Her absence from the stage is deliberate — the working class had no voice in Edwardian society. Her multiple names suggest she may be multiple women, making her a universal symbol.\n\nExam tip: Eva/Daisy is best discussed as a symbol rather than a character — she represents the human cost of capitalist selfishness. "Eva Smith" = Eve (everywoman) + Smith (most common English surname).' },
      { id: 'aic-c8', front: 'Sheila vs Mr Birling — Generational Contrast', back: 'Sheila: Learns, grows, accepts guilt, becomes morally authoritative, challenges her parents, represents hope for change.\n\nMr Birling: Refuses to learn, denies guilt, clings to status and reputation, dismisses the Inspector, represents stagnation.\n\nKey contrast: After the Inspector leaves, Birling asks "Is there any more whisky?" while Sheila is devastated — their priorities reveal everything.\n\nPriestley\'s message: The older generation is beyond saving; the younger generation carries the hope for a more equal society. This mirrors the 1945 context — the post-war generation must build a welfare state their parents\' generation would have rejected.\n\nExam tip: This is the play\'s most important structural contrast — always discuss how the generational divide maps onto Priestley\'s political message.' },
      { id: 'aic-c9', front: 'Mrs Birling vs Sheila — Motherhood and Morality', back: 'Mrs Birling: Uses her social position to deny help to a pregnant woman; cannot see past class prejudice even when faced with death.\n\nSheila: Feels visceral guilt for her much smaller role; empathises with Eva as a fellow woman.\n\nKey irony: Mrs Birling runs a women\'s charity but destroys a woman. Sheila has no charitable role but shows genuine charity of spirit.\n\nPriestley\'s message: True morality comes from empathy, not social position. Institutional charity without compassion is worthless — even harmful.\n\nExam tip: The mother-daughter contrast lets you discuss gender AND class AND generation in one analysis.' },
      { id: 'aic-c10', front: 'The Inspector vs Birling — Ideological Conflict', back: 'Birling: "A man has to make his own way." Represents capitalism, individualism, self-interest.\n\nInspector: "We are members of one body." Represents socialism, collectivism, shared responsibility.\n\nStructural point: Birling speaks first (Act 1) but the Inspector speaks last (Act 3) — Priestley gives socialism the final word.\n\nDramatic function: The Inspector dismantles Birling\'s worldview piece by piece through the evening. Every revelation proves Birling\'s philosophy of self-interest causes real human suffering.\n\nExam tip: Frame your essay around this ideological battle — it IS the play. Every character, event, and technique serves this central conflict between capitalist selfishness and socialist responsibility.' },

      // ── THEME CARDS (8) ──
      { id: 'aic-t1', front: 'Theme: Responsibility', back: 'Central message: We are all responsible for each other — ignoring this duty has fatal consequences.\n\nHow it\'s shown:\n- Each Birling contributed to Eva\'s death through selfish actions\n- Sheila and Eric accept responsibility; Mr and Mrs Birling refuse\n- The Inspector\'s final speech is a direct statement of collective responsibility\n\nKey quotes: "We are members of one body" / "fire and blood and anguish"\n\nPriestley\'s purpose: Written in 1945 as Britain debated the welfare state, Priestley argues that society must care for its most vulnerable members. The play is a dramatic argument FOR collective responsibility and AGAINST selfish individualism.\n\nExam tip: Responsibility is the play\'s thesis — every other theme connects back to it.' },
      { id: 'aic-t2', front: 'Theme: Class and Social Inequality', back: 'Central idea: The class system allows the rich to exploit the poor without consequence — until the Inspector arrives.\n\nHow it\'s shown:\n- Birling sacks Eva for asking for fair wages\n- Mrs Birling dismisses Eva\'s "fine feelings" because of her class\n- Gerald treats Daisy as a mistress, not an equal\n- Eric exploits Eva sexually because his class gives him power\n\nKey language: "girls of that class," "cheap labour," "a girl in her position"\n\nPriestley\'s purpose: Priestley exposes how class language dehumanises — the Birlings cannot see Eva as a person because their class vocabulary only has categories. The play argues that class hierarchy is morally indefensible.\n\nExam tip: Show how each character\'s treatment of Eva is enabled by the class system — it is not individual cruelty but systemic oppression.' },
      { id: 'aic-t3', front: 'Theme: Gender and Exploitation', back: 'Central idea: Women in 1912 were doubly vulnerable — exploited by both class and gender.\n\nHow it\'s shown:\n- Eva is sacked, sexually exploited, and denied charity — all because she is a working-class woman\n- Mrs Birling enforces patriarchal values despite being a woman herself\n- Sheila was initially defined by her engagement (social status through marriage)\n- Gerald\'s affair shows how men "rescued" women only to possess them\n\nPriestley\'s purpose: Eva\'s vulnerability is specifically gendered — she cannot fight back because 1912 society gave women no economic independence, legal protection, or political voice (women couldn\'t vote until 1918/1928).\n\nExam tip: Link gender to class — Eva is exploited not just as a woman but as a WORKING-CLASS woman. Mrs Birling, a wealthy woman, is complicit in her destruction.' },
      { id: 'aic-t4', front: 'Theme: Generational Divide', back: 'Central idea: The younger generation can learn and change; the older generation is set in its ways.\n\nHow it\'s shown:\n- Sheila and Eric accept guilt and want to change\n- Mr and Mrs Birling deny responsibility and try to cover up\n- After the Inspector leaves, the generations split: parents celebrate "escape," children remain haunted\n\nStructural significance: The play ends with a phone call announcing a real inspector is coming — the parents\' relief is shattered, but Sheila and Eric have already learned their lesson regardless.\n\nPriestley\'s purpose: Writing for a 1945 audience, Priestley urges the younger generation to reject their parents\' pre-war values and build a new, fairer society. The play is literally a call to action for young people.\n\nExam tip: The final phone call matters — it shows that truth catches up with those who refuse to learn. Sheila and Eric are ready; their parents are not.' },
      { id: 'aic-t5', front: 'Theme: Appearance vs Reality', back: 'Central idea: The Birling family appears respectable but is morally rotten beneath the surface.\n\nHow it\'s shown:\n- The play opens with a "celebration" that masks secrets (Eric\'s drinking, Gerald\'s affair)\n- Birling\'s confident predictions are all wrong\n- Mrs Birling\'s charity is a vehicle for class prejudice, not compassion\n- The "nice" engagement dinner becomes a courtroom\n\nDramatic structure: Priestley uses the Inspector to strip away layers of respectability, revealing the ugliness beneath. The single setting (the dining room) becomes a pressure cooker.\n\nPriestley\'s purpose: Priestley argues that the Edwardian upper class\'s respectability was a performance concealing exploitation, hypocrisy, and cruelty.\n\nExam tip: The dining room setting is key — everything happens in one room because there is nowhere to hide once the Inspector starts asking questions.' },
      { id: 'aic-t6', front: 'Theme: Capitalism vs Socialism', back: 'Central idea: The play dramatises the political argument between capitalism (Birling) and socialism (Inspector).\n\nCapitalism in the play:\n- Birling: profit before people, workers as "cheap labour," self-interest as virtue\n- Gerald: uses wealth to "keep" Daisy, treats relationships as transactions\n\nSocialism in the play:\n- Inspector: collective responsibility, empathy, equality of human worth\n- Sheila/Eric: learn to see beyond class and self-interest\n\nPriestley\'s purpose: Priestley was a committed socialist. The play is political propaganda (in the best sense) — it makes the intellectual argument for socialism through emotional storytelling. The audience feels Eva\'s suffering and understands that capitalism caused it.\n\nExam tip: Name the political ideologies explicitly in your essay — examiners reward students who connect the play to Priestley\'s socialism.' },
      { id: 'aic-t7', front: 'Theme: Guilt and Consequences', back: 'Central idea: Actions have consequences, and guilt is the appropriate response to causing harm.\n\nHow it\'s shown:\n- Each Birling\'s action contributed to Eva\'s death — the "chain of events"\n- Sheila feels instant guilt; Eric feels guilt mixed with shame\n- Mr and Mrs Birling feel no guilt — only fear of scandal\n- Gerald feels temporary guilt but quickly rationalises it away\n\nThe final phone call: Proves that consequences cannot be escaped through denial. A real inspector IS coming.\n\nPriestley\'s purpose: The play tests each character\'s capacity for guilt as a measure of their humanity. Those who feel guilt (Sheila, Eric) prove they have a conscience; those who don\'t (Mr and Mrs Birling) prove they have lost theirs.\n\nExam tip: Distinguish between guilt (moral feeling) and fear of consequences (self-interest) — the Birlings experience both, but only Sheila and Eric feel genuine guilt.' },
      { id: 'aic-t8', front: 'Theme: Time and Structure', back: 'Central idea: Priestley manipulates time to create dramatic irony and political meaning.\n\nKey time elements:\n- Set in 1912, written in 1945 — the audience knows what Birling doesn\'t (WWI, WWII, Titanic)\n- Real time: the play unfolds in a single evening with no time jumps\n- The Inspector controls the pace — he decides when each revelation comes\n- Cyclical structure: the final phone call suggests events will repeat\n\nThree unities: Priestley uses classical dramatic unities (time, place, action) to create claustrophobic intensity.\n\nPriestley\'s purpose: The time gap between setting and performance is the play\'s most powerful device — it turns every confident statement by Birling into dramatic irony. The audience is forced to judge the past from the future.\n\nExam tip: Always mention the dual time frame (1912/1945) — it is essential to understanding the play\'s political message and dramatic irony.' },

      // ── CONTEXT CARDS (7) ──
      { id: 'aic-x1', front: 'Context: 1912 vs 1945 — Why the Time Gap Matters', back: '1912 (when the play is set):\n- Rigid class hierarchy, no welfare state\n- Women couldn\'t vote\n- Workers had few rights; strikes were common\n- Titanic launched (symbol of Edwardian confidence)\n- Two years before WWI\n\n1945 (when the play was written/performed):\n- WWII just ended; Britain traumatised but hopeful\n- Labour government elected; welfare state being created\n- NHS, social housing, and nationalisation planned\n- Class barriers weakened by shared wartime suffering\n\nWhy it matters: Priestley sets the play in 1912 so the 1945 audience can see how pre-war attitudes LED to catastrophe. The audience already knows Birling is wrong about everything — this retrospective irony makes the play a powerful argument for post-war social reform.' },
      { id: 'aic-x2', front: 'Context: J.B. Priestley\'s Socialism', back: 'Who was Priestley?\n- Born 1894, Bradford (industrial northern England)\n- Fought in WWI (wounded, gassed) — saw the human cost of ruling-class decisions\n- Became a socialist broadcaster during WWII (his "Postscripts" reached millions)\n- Helped inspire the 1945 Labour landslide\n\nHis beliefs:\n- Society must care for all its members, not just the wealthy\n- The class system is morally indefensible\n- Art should challenge audiences to think and change\n\nHow it shapes the play: Every element serves Priestley\'s socialist argument — Birling represents capitalism (and is humiliated), the Inspector represents socialism (and is vindicated), and Eva represents the human cost of inequality. The play is a political act disguised as a detective story.' },
      { id: 'aic-x3', front: 'Context: Edwardian Class System', back: 'The rigid hierarchy:\n- Upper class: Landed aristocracy and wealthy industrialists (the Birlings, the Crofts)\n- Middle class: Professionals, shopkeepers\n- Working class: Factory workers, servants, labourers (Eva Smith)\n\nKey features:\n- Class determined everything: education, housing, healthcare, legal treatment\n- Working-class women were especially vulnerable — no vote, no legal protection, dependent on employers\n- Social mobility was almost impossible\n- The rich believed poverty was a moral failing, not a systemic issue\n\nIn the play: The Birlings treat Eva as disposable because her class makes her invisible to them. Each family member exploits the class system\'s power imbalance. Priestley shows that "respectability" is just privilege — not virtue.' },
      { id: 'aic-x4', front: 'Context: The Welfare State and Post-War Britain', back: 'What happened after 1945:\n- Labour won a landslide election (partly inspired by Priestley\'s broadcasts)\n- The welfare state was created: NHS (1948), social security, council housing\n- The idea: society should provide a safety net for everyone\n\nConnection to the play:\n- Eva Smith dies because there IS no safety net — no NHS, no benefits, no social housing\n- Mrs Birling\'s charity is the only "welfare" available, and it rejects Eva on class grounds\n- The Inspector\'s speech is essentially an argument FOR the welfare state\n\nExam relevance: Priestley wrote the play to persuade the 1945 audience that they MUST build a fairer society — if Eva Smith had had access to a welfare state, she might have survived. The play is propaganda for social reform.' },
      { id: 'aic-x5', front: 'Context: Women\'s Rights in 1912', back: 'Women in 1912:\n- Could not vote (suffragettes were fighting for this — some imprisoned and force-fed)\n- Limited employment: domestic service, factories, shops\n- Legally subordinate to husbands/fathers\n- Sexual double standard: men\'s affairs tolerated; women who had affairs were "ruined"\n- No contraception, no abortion rights, no maternity leave\n\nIn the play:\n- Eva is sacked from TWO jobs with no legal recourse\n- Gerald "keeps" her as a mistress — she has no economic independence\n- Eric assaults her — she has no legal protection\n- Mrs Birling denies her charity help for being an unmarried mother\n\nPriestley\'s point: Eva\'s fate is specifically a consequence of being female AND working class in 1912. Every door is closed to her because of her gender and class combined.' },
      { id: 'aic-x6', front: 'Context: The Well-Made Play and Dramatic Unities', back: 'Priestley\'s dramatic choices:\n- One setting (the Birling dining room) — no escape, claustrophobic\n- Real time (the play unfolds in one continuous evening)\n- One central action (the investigation of Eva\'s death)\n\nWhy this matters:\n- The single room becomes a courtroom and a confessional\n- No scene changes = no relief for the audience or the characters\n- The Inspector controls the flow — he is the playwright within the play\n\nThe detective genre:\n- Priestley uses the "whodunit" structure but subverts it — EVERYONE did it\n- The mystery is not "who killed Eva?" but "will the Birlings accept responsibility?"\n- The twist: the Inspector may not be real, but the guilt IS real\n\nExam tip: Discuss Priestley\'s structural choices as deliberate — the form of the play IS part of its argument.' },
      { id: 'aic-x7', front: 'Context: Dramatic Irony in An Inspector Calls', back: 'What the 1945 audience knows that Birling doesn\'t:\n- The Titanic sank (April 1912) — Birling says it\'s "unsinkable"\n- WWI happened (1914-1918) — Birling says war is impossible\n- WWII happened (1939-1945) — Birling says technology will bring peace\n- The Russian Revolution happened (1917) — Birling dismisses socialist "cranks"\n\nEffect: Every prediction Birling makes is catastrophically wrong. This isn\'t just comedy — it\'s political demolition. If Birling is wrong about the Titanic, war, and Russia, he must also be wrong about "a man has to look after himself."\n\nPriestley\'s technique: By making Birling a prophet of failure, Priestley ensures the audience cannot trust ANYTHING he says. His entire capitalist philosophy is discredited before the Inspector even arrives.\n\nExam tip: Always explain dramatic irony in terms of the DUAL audience — what it means for 1912 characters vs 1945 viewers.' },
    ],
  },

  // ─────────────────────────────────────────────
  // LORD OF THE FLIES — COMPREHENSIVE (35 cards)
  // ─────────────────────────────────────────────
  {
    id: 'lotf-comprehensive',
    title: 'Lord of the Flies — Comprehensive',
    description: '35 exam-ready cards covering quotes, characters, themes, and symbols for Lord of the Flies',
    category: 'Set Texts',
    board: 'AQA',
    cards: [
      // ── QUOTE CARDS (12) ──
      { id: 'lotf-q1', front: '"Maybe there is a beast... maybe it\'s only us."', back: 'Speaker: Simon (Chapter 5)\n\nMeaning: Simon suggests the "beast" is not an external creature but something inside the boys themselves — human nature.\n\nTechniques: Ellipsis creates hesitation (reflecting fear of the truth), philosophical insight, foreshadowing.\n\nThemes: Innate evil, civilisation vs savagery, fear.\n\nExam point: Simon is the only character who understands the truth — the beast is humanity\'s capacity for evil. Golding uses Simon as a Christ-like figure who perceives spiritual truths others cannot. His insight is rejected and he is later murdered for it, suggesting society destroys those who reveal uncomfortable truths.' },
      { id: 'lotf-q2', front: '"Kill the pig. Cut her throat. Spill her blood."', back: 'Speaker: Jack\'s hunters (Chapter 4 onwards, evolving)\n\nMeaning: The hunting chant that becomes increasingly violent and ritualistic as the boys descend into savagery.\n\nTechniques: Imperative verbs, tricolon, monosyllabic words, tribal rhythm, escalating violence.\n\nThemes: Savagery, mob mentality, loss of civilisation, violence.\n\nExam point: The chant evolves throughout the novel — it starts as play but becomes deadly ritual. The rhythmic, monosyllabic language strips away complexity and intellect, reducing the boys to primal instinct. Golding shows how language itself can be weaponised to override reason and enable violence.' },
      { id: 'lotf-q3', front: '"Ralph wept for the end of innocence, the darkness of man\'s heart."', back: 'Speaker: Narrator (Final chapter)\n\nMeaning: Ralph cries not just for Piggy and Simon but for the loss of the boys\' innocence and the revelation of human evil.\n\nTechniques: Emotive verb "wept," abstract nouns, metaphor ("darkness of man\'s heart"), tricolon.\n\nThemes: Loss of innocence, innate evil, civilisation.\n\nExam point: This is Golding\'s thesis statement, placed at the novel\'s conclusion. Ralph has witnessed the full spectrum of human behaviour — from cooperation to murder — and understands that evil is not external but internal. The "darkness" is permanent and universal; it exists in ALL hearts, not just Jack\'s. The naval officer\'s arrival does not restore innocence — it merely interrupts savagery.' },
      { id: 'lotf-q4', front: '"The thing is — fear can\'t hurt you any more than a dream."', back: 'Speaker: Jack (Chapter 2)\n\nMeaning: Jack dismisses the littluns\' fear of the beast as childish — but later exploits that same fear for power.\n\nTechniques: Declarative, dismissive tone, dramatic irony.\n\nThemes: Fear, power, manipulation.\n\nExam point: The dramatic irony is crucial — Jack says fear can\'t hurt, but fear becomes the most destructive force on the island. Later, Jack WEAPONISES fear of the beast to control the boys. Golding shows how authoritarians first dismiss fear, then create it. Jack\'s journey from dismissing to exploiting fear mirrors the rise of fascist leaders.' },
      { id: 'lotf-q5', front: '"Which is better — to have rules and agree, or to hunt and kill?"', back: 'Speaker: Piggy (Chapter 11)\n\nMeaning: Piggy makes his final stand for civilisation, framing the island\'s conflict as a clear moral choice.\n\nTechniques: Rhetorical question, antithesis (rules vs killing), balanced structure.\n\nThemes: Civilisation vs savagery, democracy, reason.\n\nExam point: Piggy presents the choice as obvious — but the boys have already chosen savagery. His rhetorical question goes unanswered because Roger kills him moments later. Golding\'s devastating point: reason and logic are powerless against violence. Democracy requires consent, and when consent is withdrawn, civilisation collapses.' },
      { id: 'lotf-q6', front: '"I ought to be chief... because I\'m chapter chorister and head boy."', back: 'Speaker: Jack Merridew (Chapter 1)\n\nMeaning: Jack claims leadership based on his institutional authority and social status.\n\nTechniques: First person assertion, appeal to authority, entitlement.\n\nThemes: Power, authority, civilisation, class.\n\nExam point: Jack\'s claim reveals his understanding of power as entitlement rather than consent. He assumes hierarchy from the "old world" should transfer to the island. When democracy (the vote) rejects him, he creates his own authoritarian system based on fear and violence instead. Golding shows how those who feel entitled to power are the most dangerous when denied it.' },
      { id: 'lotf-q7', front: '"His mind was crowded with memories... of the knowledge that they had outwitted a living thing, imposed their will upon it, taken away its life like a long satisfying drink."', back: 'Speaker: Narrator, describing Jack after first kill (Chapter 4)\n\nMeaning: Jack experiences the first kill as intoxicating — power over life and death becomes addictive.\n\nTechniques: Long sentence mimics intoxication, simile ("like a long satisfying drink"), semantic field of domination ("outwitted," "imposed," "taken away").\n\nThemes: Savagery, power, violence as pleasure.\n\nExam point: The simile comparing killing to drinking reveals that violence satisfies a thirst — it becomes a need, not just an action. Golding suggests humans have an innate appetite for dominance that civilisation suppresses but cannot eliminate. Once Jack tastes power over life, he can never go back to rules and democracy.' },
      { id: 'lotf-q8', front: '"Roger gathered a handful of stones and began to throw them at Henry."', back: 'Speaker: Narrator (Chapter 4)\n\nMeaning: Roger throws stones near (not at) a littlun, restrained by "the taboo of the old life" — civilisation\'s last hold on him.\n\nTechniques: Simple declarative, understated violence, foreshadowing.\n\nThemes: Civilisation vs savagery, innate evil, the thin veneer of order.\n\nExam point: Roger deliberately misses because social conditioning still restrains him — but Golding makes clear this restraint is learned, not natural. Later, Roger kills Piggy with a boulder, showing what happens when civilisation\'s "taboo" fully dissolves. The progression from small stones to a killing boulder tracks the novel\'s descent into savagery.' },
      { id: 'lotf-q9', front: '"Fancy thinking the Beast was something you could hunt and kill!"', back: 'Speaker: The Lord of the Flies / the pig\'s head (Chapter 8)\n\nMeaning: The beast cannot be hunted because it lives inside every human being.\n\nTechniques: Exclamatory, mocking tone, dramatic irony, personification (the head "speaks").\n\nThemes: Innate evil, illusion vs reality, fear.\n\nExam point: The Lord of the Flies (Beelzebub — the Devil) speaks the novel\'s central truth: evil is not external but internal. You cannot kill it because it IS you. Golding subverts the boys\' adventure-story expectations — there is no monster to defeat. The real horror is that the "beast" is human nature itself, and it is inescapable.' },
      { id: 'lotf-q10', front: '"The rules!" shouted Ralph. "You\'re breaking the rules!" "Who cares?"', back: 'Speaker: Ralph and Jack (Chapter 5)\n\nMeaning: Ralph desperately appeals to the rules; Jack dismisses them entirely.\n\nTechniques: Exclamatory, dialogue contrast, short sentences showing conflict.\n\nThemes: Civilisation vs savagery, democracy vs autocracy, rules and order.\n\nExam point: This exchange encapsulates the novel\'s central conflict in miniature. Ralph believes rules have inherent authority; Jack understands that rules only have power if people choose to follow them. Once Jack says "who cares?", civilisation on the island is effectively over — the social contract is broken. Golding shows democracy\'s fatal weakness: it depends on voluntary compliance.' },
      { id: 'lotf-q11', front: '"The conch exploded into a thousand white fragments and ceased to exist."', back: 'Speaker: Narrator (Chapter 11)\n\nMeaning: Roger\'s boulder kills Piggy and destroys the conch simultaneously — democracy and reason die together.\n\nTechniques: Violent verb "exploded," hyperbole ("thousand"), declarative finality ("ceased to exist").\n\nThemes: Death of civilisation, violence, democracy.\n\nExam point: The conch\'s destruction is not accidental — Golding ensures it dies with Piggy because they represent the same thing: rational, democratic civilisation. "Ceased to exist" is chillingly final — civilisation does not fade gradually but is violently obliterated. After this moment, there are no rules, no democracy, and no restraint.' },
      { id: 'lotf-q12', front: '"He began to dance and his laughter became a bloodthirsty snarling."', back: 'Speaker: Narrator, describing Jack (Chapter 4)\n\nMeaning: Jack\'s behaviour transforms from play to primal aggression as he paints his face.\n\nTechniques: Zoomorphism ("snarling"), semantic shift from "laughter" to "bloodthirsty," transformation imagery.\n\nThemes: Savagery, loss of identity, dehumanisation.\n\nExam point: The face paint is Jack\'s key symbol — it hides his identity and liberates his savage instincts. Golding shows that civilised behaviour depends on being seen and recognised. Behind a mask, without social accountability, the "beast" within is freed. This connects to Golding\'s broader argument about anonymity enabling atrocity.' },

      // ── CHARACTER CARDS (8) ──
      { id: 'lotf-c1', front: 'Ralph — Character Profile', back: 'Role: Elected leader, represents democracy, civilisation, and order.\n\nKey traits: Fair-minded, responsible, increasingly desperate, capable of violence (participates in Simon\'s murder).\n\nKey actions: Establishes rules and the signal fire; tries to maintain order; hunted by Jack\'s tribe at the end.\n\nGolding\'s purpose: Ralph represents democratic leadership — well-intentioned but fragile. His failure shows that democracy cannot survive when people choose savagery. Crucially, Ralph also participates in Simon\'s killing, proving that even the "civilised" are capable of evil.\n\nExam tip: Ralph is not purely good — his participation in Simon\'s murder is essential to Golding\'s argument that ALL humans carry darkness, not just the "bad" ones.' },
      { id: 'lotf-c2', front: 'Jack Merridew — Character Profile', back: 'Role: Antagonist, choir leader turned tribal chief, represents authoritarianism and savagery.\n\nKey traits: Charismatic, violent, manipulative, power-hungry, uses fear and spectacle to control.\n\nKey actions: Leads the hunters; creates his own tribe through fear and feasting; orders the hunt for Ralph.\n\nGolding\'s purpose: Jack represents the appeal of fascism — he offers excitement, meat, and a clear enemy (the beast), while Ralph only offers rules and delayed rescue. Golding shows why authoritarian leaders win followers: they appeal to instinct, not reason.\n\nExam tip: Jack does not "become" evil — Golding suggests the capacity was always there, restrained by civilisation. The island merely removes the restraints.' },
      { id: 'lotf-c3', front: 'Piggy — Character Profile', back: 'Role: Ralph\'s advisor, represents intellect, science, and rational thought.\n\nKey traits: Intelligent, logical, physically weak, socially excluded (asthma, glasses, weight), loyal to rules.\n\nKey actions: Suggests using the conch; maintains the intellectual argument for civilisation; killed by Roger.\n\nGolding\'s purpose: Piggy proves that intelligence alone cannot save civilisation — without physical power or social status, reason is ignored. His death (alongside the conch\'s destruction) symbolises the death of rational civilisation.\n\nExam tip: Piggy is marginalised from the start — even Ralph mocks him. Golding shows that society undervalues intellect and victimises the vulnerable, even in supposedly "civilised" groups.' },
      { id: 'lotf-c4', front: 'Simon — Character Profile', back: 'Role: The moral and spiritual centre of the novel, a Christ-like figure.\n\nKey traits: Quiet, kind, perceptive, epileptic (his "fits" give him visions), compassionate, solitary.\n\nKey actions: Feeds the littluns; retreats to the forest for solitude; discovers the "beast" is a dead parachutist; is murdered by the group.\n\nGolding\'s purpose: Simon represents innate human goodness and spiritual insight. He alone understands that the beast is "only us." His murder — by ALL the boys, including Ralph — is the novel\'s climactic tragedy. Like Christ, he brings truth and is killed for it.\n\nExam tip: Simon\'s murder is the novel\'s moral turning point — after killing the one truly good person, the boys\' descent into savagery becomes irreversible.' },
      { id: 'lotf-c5', front: 'Roger — Character Profile', back: 'Role: Jack\'s enforcer, represents pure sadism and the human capacity for cruelty.\n\nKey traits: Silent, menacing, increasingly violent, finds pleasure in others\' pain.\n\nKey actions: Throws stones at littluns (but misses); kills Piggy with a boulder; tortures Samneric.\n\nGolding\'s purpose: Roger is the novel\'s most disturbing character because his violence is not motivated by power (like Jack\'s) but by PLEASURE. He represents the human capacity for cruelty that exists beneath civilisation\'s surface.\n\nProgression: Stones (restrained) → sharpened stick → boulder (unrestrained) — this arc tracks the complete dissolution of moral restraint.\n\nExam tip: Roger, not Jack, kills Piggy — Golding shows that the most dangerous people are not leaders but those who enjoy cruelty for its own sake.' },
      { id: 'lotf-c6', front: 'Samneric (Sam and Eric) — Character Profile', back: 'Role: The twins represent the ordinary person — loyal to civilisation but ultimately conforming to power.\n\nKey traits: Inseparable, loyal to Ralph, easily frightened, eventually forced to join Jack\'s tribe.\n\nKey actions: Tend the signal fire; mistake the dead parachutist for the beast; are captured and tortured into joining Jack.\n\nGolding\'s purpose: Samneric show that most people are not heroes or villains — they are followers who side with whoever holds power. Their forced conversion to Jack\'s tribe illustrates how ordinary people comply with tyranny out of fear.\n\nExam tip: Samneric\'s surrender is realistic, not cowardly — Golding shows that resisting tyranny requires extraordinary courage that most people do not possess.' },
      { id: 'lotf-c7', front: 'The Naval Officer — Character Profile', back: 'Role: Appears at the very end, represents the "adult" civilised world that rescues the boys.\n\nKey traits: Uniformed, authoritative, embarrassed by the boys\' savagery, represents British naval power.\n\nIrony: The officer is fighting in a WAR — the adult world is engaged in the same violence the boys have been. He represents civilisation\'s hypocrisy: adults condemn children\'s savagery while committing it on a global scale.\n\nGolding\'s purpose: The "rescue" is deeply ironic — the boys are saved from their small-scale savagery and returned to large-scale, industrialised savagery (WWII). Golding denies the reader any comfortable resolution.\n\nExam tip: The officer\'s arrival does NOT mean civilisation has triumphed — it means the cycle of violence continues at a larger scale.' },
      { id: 'lotf-c8', front: 'The Littluns — Character Profile', back: 'Role: The youngest boys on the island, represent the vulnerable masses in society.\n\nKey traits: Fearful, dependent, easily manipulated, plagued by nightmares of the beast.\n\nKey function: Their fear of the beast gives it power — Jack exploits their terror to seize control.\n\nGolding\'s purpose: The littluns represent ordinary citizens in a political allegory — they are controlled through fear and spectacle, first by the conch (democracy) then by Jack (authoritarianism). Their nightmares about the beast show how fear is the most powerful political tool.\n\nExam tip: The littluns\' fear CREATES the beast — Golding shows that collective fear generates the very monsters it imagines, which tyrants then exploit.' },

      // ── THEME CARDS (8) ──
      { id: 'lotf-t1', front: 'Theme: Civilisation vs Savagery', back: 'Central idea: Civilisation is a fragile, artificial construct; savagery is humanity\'s natural state.\n\nHow it\'s shown:\n- Ralph\'s democratic rules collapse as Jack\'s tribal savagery grows\n- The boys\' descent: choir → hunters → tribe → murderers\n- Symbols track it: conch (order) vs face paint (savagery); signal fire (rescue/hope) vs hunting fire\n\nKey moments: Roger\'s stones → Simon\'s murder → Piggy\'s death → Ralph hunted\n\nGolding\'s argument: Civilisation is not innate — it is learned and maintained through effort. Without external enforcement (adults, laws, punishment), it collapses rapidly. Savagery is the default human state; civilisation is the exception.\n\nExam tip: Golding wrote this in response to "The Coral Island" (1857), which showed British boys as inherently civilised. Golding\'s novel is a deliberate, dark inversion.' },
      { id: 'lotf-t2', front: 'Theme: Innate Human Evil', back: 'Central idea: Evil is not external but lives within every human being.\n\nHow it\'s shown:\n- The "beast" is revealed to be "only us" (Simon\'s insight)\n- The Lord of the Flies confirms: "I\'m part of you"\n- Even Ralph participates in Simon\'s murder\n- Roger\'s sadism emerges without any external cause\n\nGolding\'s argument: Golding, a WWII veteran who witnessed the Holocaust and atomic bombing, rejected the idea that humans are fundamentally good. The novel argues that evil is not caused by society — it IS human nature. Civilisation can restrain it but never eliminate it.\n\nExam tip: Connect to Golding\'s biography — he said "I began to see what people were capable of doing" during the war. The novel is his response to witnessing human evil firsthand.' },
      { id: 'lotf-t3', front: 'Theme: Power and Leadership', back: 'Central idea: Democracy requires willing participation; authoritarianism succeeds through fear and spectacle.\n\nTwo models of leadership:\n- Ralph: Elected, rules-based, focused on rescue (long-term), boring but necessary\n- Jack: Self-appointed, fear-based, focused on hunting (immediate pleasure), exciting but destructive\n\nWhy Jack wins: He offers meat, excitement, an enemy to fear, and a tribe to belong to. Ralph only offers rules and hard work. Golding shows that democratic leadership is inherently less appealing than authoritarian spectacle.\n\nGolding\'s argument: Democracy is fragile because it asks people to sacrifice immediate gratification for long-term good — most people, given the choice, will follow the leader who gives them what they want NOW.\n\nExam tip: Link to 1930s/40s fascism — Golding saw how Hitler and Mussolini used spectacle, fear, and scapegoating to win power, exactly as Jack does.' },
      { id: 'lotf-t4', front: 'Theme: Loss of Innocence', back: 'Central idea: The boys arrive as innocent children and leave as killers — the island reveals what was always inside them.\n\nProgression:\n- Chapter 1: Swimming, exploring, playing — childhood adventure\n- Middle chapters: Hunting, face paint, rituals — gradual descent\n- Final chapters: Murder, torture, manhunt — complete savagery\n\nKey moment: "Ralph wept for the end of innocence, the darkness of man\'s heart" — Ralph\'s final understanding.\n\nGolding\'s argument: Innocence is not a permanent state — it is simply ignorance of one\'s own capacity for evil. The island does not CORRUPT the boys; it REVEALS them. The loss of innocence is not a tragedy but a confrontation with truth.\n\nExam tip: The boys\' youth makes Golding\'s argument more powerful — if CHILDREN can descend into murder, what hope is there for adults? The novel rejects Romantic ideas of childhood innocence.' },
      { id: 'lotf-t5', front: 'Theme: Fear', back: 'Central idea: Fear is the most powerful force on the island — it drives behaviour, creates the beast, and enables tyranny.\n\nHow fear operates:\n- The littluns\' nightmares create the idea of the beast\n- Jack exploits fear to seize power ("I\'ll protect you from the beast")\n- Fear of exclusion makes boys join Jack\'s tribe\n- Fear of the unknown (the dead parachutist) prevents rational investigation\n\nGolding\'s argument: Fear is the enemy of reason. Once fear takes hold, people abandon logic, democracy, and morality in favour of any leader who promises safety. The beast is created by fear, sustained by fear, and used to control through fear.\n\nExam tip: The beast\'s power is entirely psychological — it does not exist, yet it destroys the island\'s civilisation. Golding shows that imaginary threats are more dangerous than real ones because they cannot be defeated.' },
      { id: 'lotf-t6', front: 'Theme: The Failure of Reason', back: 'Central idea: Intelligence and logic are powerless against primal instinct and mob mentality.\n\nHow it\'s shown:\n- Piggy\'s glasses (intellect) are stolen and used to make fire (destruction)\n- Piggy\'s rational arguments are ignored, mocked, and finally silenced by murder\n- Simon\'s truthful insight is met with violence, not acceptance\n- The conch (rational debate) is destroyed\n\nGolding\'s argument: The Enlightenment idea that reason will save humanity is naive. When survival instincts and tribal loyalties are activated, reason becomes irrelevant. Piggy\'s death proves that being RIGHT does not protect you — power does.\n\nExam tip: Piggy asks "Which is better — to have rules and agree, or to hunt and kill?" The answer, on the island, is that it doesn\'t matter which is "better" — only which is stronger.' },
      { id: 'lotf-t7', front: 'Theme: Identity and the Mask', back: 'Central idea: When identity is hidden, moral restraint disappears — the mask liberates the savage within.\n\nHow it\'s shown:\n- Jack\'s face paint transforms him: "He began to dance and his laughter became a bloodthirsty snarling"\n- The painted hunters lose individual identity and become a mob\n- Simon\'s murder happens in darkness and frenzy — the boys do not "see" what they do\n- Roger\'s violence escalates as he becomes increasingly anonymous\n\nGolding\'s argument: Civilised behaviour depends on being seen and recognised. Anonymity — whether through masks, crowds, or darkness — removes accountability and enables atrocity. This connects to Golding\'s understanding of mob violence and war.\n\nExam tip: The face paint is more than costume — it is a psychological device that separates the "civilised self" from the "savage self."' },
      { id: 'lotf-t8', front: 'Theme: Order vs Chaos (Structure)', back: 'Central idea: The novel\'s structure mirrors the boys\' descent from order to chaos.\n\nStructural arc:\n- Opening: Organised assembly, rules, elected leader, division of labour\n- Middle: Competing factions, broken rules, escalating violence\n- End: Total chaos — manhunt, fire consuming the island\n\nKey structural devices:\n- The conch: physically deteriorates as democracy weakens\n- The signal fire: abandoned as rescue becomes less important than hunting\n- The island itself: initially paradise, finally burning hellscape\n\nGolding\'s technique: The novel\'s form enacts its argument — the increasingly fragmented narrative mirrors the disintegration of civilisation. Chapter lengths and focus shift from community to violence.\n\nExam tip: Always connect structure to meaning — the novel does not just describe the collapse of order, it performs it.' },

      // ── SYMBOL CARDS (7) ──
      { id: 'lotf-s1', front: 'Symbol: The Conch Shell', back: 'What it is: A large shell Ralph finds and uses to call assemblies. Whoever holds the conch has the right to speak.\n\nWhat it represents: Democracy, order, civilised discourse, the rule of law.\n\nProgression:\n- Found and valued (Chapter 1) — democracy established\n- Increasingly ignored (middle chapters) — democracy weakened\n- "The conch exploded into a thousand white fragments and ceased to exist" (Chapter 11) — democracy destroyed\n\nKey detail: The conch fades from bright pink to near-white — its physical deterioration mirrors democracy\'s decline.\n\nExam point: The conch only has power because the boys AGREE it has power — just like laws in a democracy. Once Jack says "the conch doesn\'t count," he reveals that democratic authority is consensual, not absolute. When the conch is destroyed, civilisation dies with it.' },
      { id: 'lotf-s2', front: 'Symbol: The Beast', back: 'What it is: A feared creature the boys believe lives on the island. It is eventually revealed to be a dead parachutist — and, more importantly, "only us."\n\nWhat it represents: The evil within humanity; irrational fear; the unknown.\n\nProgression:\n- Littluns\' nightmares → "snake-thing" → "beast from water" → "beast from air" (dead parachutist) → "maybe it\'s only us"\n\nKey insight: "Fancy thinking the Beast was something you could hunt and kill!" (Lord of the Flies to Simon)\n\nExam point: The beast is Golding\'s central metaphor — evil is not external but internal. The boys\' attempts to hunt and appease the beast are futile because they ARE the beast. Jack exploits the beast to gain power, offering sacrifices and protection. The beast is fear given form, and fear is the novel\'s most destructive force.' },
      { id: 'lotf-s3', front: 'Symbol: The Signal Fire', back: 'What it is: A fire maintained on the mountain to attract passing ships for rescue.\n\nWhat it represents: Hope, connection to civilisation, rational priorities, cooperation.\n\nProgression:\n- Established with enthusiasm (Chapter 2) — hope for rescue\n- Left to die when hunters abandon duty (Chapter 4) — a ship passes unseen\n- Abandoned entirely as Jack\'s tribe takes over — rescue ceases to matter\n- Final fire: Jack burns the island to smoke Ralph out — ironically attracts the naval officer\n\nExam point: The fire\'s fate tracks the boys\' relationship with civilisation. When they tend it, they prioritise rescue (future, reason). When they abandon it, they prioritise hunting (present, instinct). The final irony — Jack\'s destructive fire achieves what Ralph\'s civilised fire could not — shows Golding\'s dark humour about how salvation often comes through chaos.' },
      { id: 'lotf-s4', front: 'Symbol: Piggy\'s Glasses', back: 'What it is: Piggy\'s spectacles, essential for his vision and used to start fires.\n\nWhat they represent: Intellect, science, rational thought, technological power.\n\nProgression:\n- Used to light the signal fire (Chapter 2) — reason serves civilisation\n- One lens broken by Jack (Chapter 4) — intellect diminished\n- Stolen by Jack\'s tribe (Chapter 10) — reason conquered by savagery\n- Used to make Jack\'s cooking fire — intellect serves savagery\n\nExam point: The glasses are the island\'s most valuable tool — they represent humanity\'s ability to harness nature through science. But technology is morally neutral: it serves whoever controls it. When Jack steals the glasses, Golding shows that knowledge and technology in the wrong hands become tools of destruction, not progress.' },
      { id: 'lotf-s5', front: 'Symbol: The Lord of the Flies (Pig\'s Head)', back: 'What it is: A sow\'s head impaled on a stake by Jack\'s hunters as an offering to the beast. Simon encounters it and it "speaks" to him.\n\nWhat it represents: The Devil (Beelzebub literally means "Lord of the Flies"), innate human evil, the beast within.\n\nKey quote: "I\'m part of you... I\'m the reason why it\'s no go. Why things are what they are."\n\nExam point: The pig\'s head is the novel\'s title symbol and its philosophical core. Surrounded by buzzing flies (decay, death, corruption), it tells Simon that evil cannot be escaped because it is part of human nature. The "conversation" may be Simon\'s hallucination (he is epileptic), but the truth it reveals is real. Golding names his novel after the Devil because his subject is the evil within humanity.' },
      { id: 'lotf-s6', front: 'Symbol: Face Paint', back: 'What it is: Clay and charcoal the hunters apply to their faces, initially for camouflage.\n\nWhat it represents: Loss of identity, liberation from civilisation\'s moral restraint, the mask that enables savagery.\n\nKey quote: "He looked in astonishment, no longer at himself but at an awesome stranger" — Jack seeing his painted reflection.\n\nProgression: Camouflage → tribal identity → psychological transformation → mob anonymity\n\nExam point: The face paint is Golding\'s metaphor for how anonymity enables evil. Jack becomes "an awesome stranger" — the paint separates him from his civilised self and frees his savage instincts. This connects to real-world phenomena: soldiers dehumanise through uniforms, mobs through anonymity, executioners through masks. Civilisation depends on being seen as yourself.' },
      { id: 'lotf-s7', front: 'Symbol: The Island Itself', back: 'What it is: An uninhabited tropical island, initially described as paradise.\n\nWhat it represents: A microcosm of the world; an Eden that becomes Hell; a blank slate for human nature.\n\nProgression:\n- Arrival: "This belongs to us" — paradise, Garden of Eden, adventure\n- Middle: Divided territory, Castle Rock vs beach — political division\n- End: Burning, destroyed — humanity ruins everything it touches\n\nKey detail: The island is shaped like a boat — but it is going nowhere. The boys are stranded with themselves.\n\nExam point: Golding deliberately strips away all external influences (adults, laws, society) to isolate human nature. The island is a laboratory. If the boys were inherently good, the island would remain paradise. Instead, they destroy it — proving Golding\'s thesis that human nature, left unchecked, tends toward destruction.' },
    ],
  },

  // ─────────────────────────────────────────────
  // ANIMAL FARM — COMPREHENSIVE (35 cards)
  // ─────────────────────────────────────────────
  {
    id: 'af-comprehensive',
    title: 'Animal Farm — Comprehensive',
    description: '35 exam-ready cards covering quotes, characters, themes, and allegory for Animal Farm',
    category: 'Set Texts',
    board: 'AQA',
    cards: [
      // ── QUOTE CARDS (12) ──
      { id: 'af-q1', front: '"All animals are equal, but some animals are more equal than others."', back: 'Speaker: The pigs\' final commandment (Chapter 10)\n\nMeaning: The original principle of equality has been corrupted into a justification for privilege — the pigs are now the ruling class.\n\nTechniques: Paradox, oxymoron ("more equal"), corruption of language, dark humour.\n\nThemes: Corruption of power, propaganda, inequality, betrayal of revolution.\n\nExam point: This is Orwell\'s most famous line — a masterclass in how language is manipulated to justify tyranny. The sentence is logically absurd but politically effective. Orwell shows that totalitarian regimes don\'t abolish the language of equality — they redefine it. The pigs have not abandoned the revolution\'s ideals; they have hollowed them out from the inside.' },
      { id: 'af-q2', front: '"Four legs good, two legs bad."', back: 'Speaker: The sheep (taught by Snowball, later changed to "Four legs good, two legs BETTER")\n\nMeaning: Originally a simplification of Animalism; later reversed to justify the pigs walking on two legs.\n\nTechniques: Repetition, slogan, propaganda, binary opposition, bleating (mindless repetition).\n\nThemes: Propaganda, manipulation, education, mob mentality.\n\nExam point: Orwell shows how propaganda works: complex ideas are reduced to simple slogans that can be chanted without thinking. The sheep don\'t understand what they\'re saying — they just repeat it. When the slogan is reversed, the sheep switch without question. Orwell warns that an uneducated populace cannot distinguish truth from manipulation.' },
      { id: 'af-q3', front: '"The creatures outside looked from pig to man, and from man to pig... but already it was impossible to say which was which."', back: 'Speaker: Narrator (Final lines, Chapter 10)\n\nMeaning: The pigs have become indistinguishable from the humans they overthrew — the revolution has come full circle.\n\nTechniques: Cyclical structure, dramatic irony, visual imagery, parallel structure.\n\nThemes: Corruption of power, revolution betrayed, cyclical history.\n\nExam point: This is Orwell\'s devastating conclusion — revolution does not create equality but merely replaces one ruling class with another. The pigs now walk upright, wear clothes, carry whips, and socialise with humans. Orwell argues that power itself corrupts, regardless of who holds it. The circular ending suggests this pattern is inescapable.' },
      { id: 'af-q4', front: '"I will work harder."', back: 'Speaker: Boxer (his personal motto)\n\nMeaning: Boxer\'s response to every problem is to work harder — blind loyalty and physical effort.\n\nTechniques: Simple declarative, repetition throughout the novel, dramatic irony.\n\nThemes: Exploitation, loyalty, the working class, blind obedience.\n\nExam point: Boxer\'s motto is tragic because his loyalty is exploited — he works himself to exhaustion and is sold to the knacker\'s yard. Orwell shows how totalitarian regimes exploit the working class\'s willingness to sacrifice. Boxer\'s strength builds the windmill (industrialisation) but he receives nothing in return. His trust in "Napoleon is always right" proves that loyalty without critical thinking is self-destructive.' },
      { id: 'af-q5', front: '"Napoleon is always right."', back: 'Speaker: Boxer (his second motto)\n\nMeaning: Boxer places absolute trust in Napoleon\'s leadership, refusing to question any decision.\n\nTechniques: Declarative, absolute statement ("always"), dramatic irony, cult of personality.\n\nThemes: Blind obedience, totalitarianism, propaganda, betrayal.\n\nExam point: This motto represents the most dangerous attitude in a dictatorship — unquestioning loyalty. Boxer is strong enough to overthrow Napoleon but too loyal to try. Orwell shows that dictators survive not through their own strength but through the obedience of those who could resist. Boxer\'s faith makes him the regime\'s most valuable tool and its most tragic victim.' },
      { id: 'af-q6', front: '"No animal shall sleep in a bed — with sheets."', back: 'Speaker: The modified commandment (Chapter 6)\n\nMeaning: The pigs have started sleeping in beds but add "with sheets" to the commandment to technically avoid breaking it.\n\nTechniques: Manipulation of language, addition of qualifier, gaslighting, dramatic irony.\n\nThemes: Propaganda, corruption, revisionism, abuse of power.\n\nExam point: Orwell demonstrates how totalitarian regimes rewrite rules to suit themselves. The animals KNOW the commandment has changed but cannot prove it — Squealer has already altered the wall. This mirrors Stalin\'s revision of Soviet history: the past is not fixed but is whatever the Party says it is. Orwell warns that without a free press and education, the truth becomes whatever those in power declare.' },
      { id: 'af-q7', front: '"Man is the only creature that consumes without producing."', back: 'Speaker: Old Major (Chapter 1)\n\nMeaning: Old Major argues that humans exploit animals\' labour without contributing anything — the foundation of Animalism.\n\nTechniques: Declarative, persuasive rhetoric, antithesis (consumes vs produces), generalisation.\n\nThemes: Exploitation, revolution, class struggle, labour.\n\nExam point: Old Major\'s speech parallels Marx\'s Communist Manifesto — the ruling class (humans/bourgeoisie) profits from the working class\'s (animals/proletariat) labour. The irony is that the pigs eventually do exactly what Old Major condemns: they consume without producing, living off other animals\' work. Orwell shows that revolutionary rhetoric can be genuine in its origin but corrupted in its application.' },
      { id: 'af-q8', front: '"Squealer could turn black into white."', back: 'Speaker: Narrator (Chapter 2)\n\nMeaning: Squealer is so persuasive he can make animals believe the opposite of what they\'ve seen with their own eyes.\n\nTechniques: Hyperbole, metaphor, foreshadowing, characterisation through reputation.\n\nThemes: Propaganda, manipulation, truth vs lies.\n\nExam point: Squealer represents Pravda (the Soviet state newspaper) and propaganda in general. His ability to "turn black into white" is not magic but technique — he uses statistics, rhetorical questions ("Surely, comrades, you do not want Jones back?"), and fear to override evidence. Orwell warns that propaganda doesn\'t need to be believable — it just needs to be repeated more loudly than the truth.' },
      { id: 'af-q9', front: '"The only good human being is a dead one."', back: 'Speaker: Snowball, paraphrasing Old Major\'s philosophy (Chapter 4)\n\nMeaning: The animals\' revolutionary ideology dehumanises the enemy completely.\n\nTechniques: Absolute statement, dehumanisation, dark humour, foreshadowing.\n\nThemes: Revolution, extremism, dehumanisation, violence.\n\nExam point: Orwell shows how revolutionary movements dehumanise their opponents to justify violence. This mirrors how the Bolsheviks demonised the bourgeoisie. The irony is that the pigs will later adopt human behaviours while maintaining anti-human rhetoric — the enemy is useful as long as it distracts from the pigs\' own corruption.' },
      { id: 'af-q10', front: '"All that year the animals worked like slaves."', back: 'Speaker: Narrator (Chapter 6)\n\nMeaning: The animals work even harder than they did under Jones — the revolution has made them less free, not more.\n\nTechniques: Simile ("like slaves"), dramatic irony, understated narrator.\n\nThemes: Exploitation, betrayal of revolution, labour, irony.\n\nExam point: The simile is devastating — the animals overthrew their "master" only to become slaves to a new one. Orwell\'s narrator states this fact without commentary, forcing the reader to recognise the irony themselves. This parallels Soviet industrialisation under Stalin, where workers suffered terrible conditions building the Five-Year Plans while being told they were building paradise.' },
      { id: 'af-q11', front: '"Surely, comrades, you do not want Jones back?"', back: 'Speaker: Squealer (used repeatedly)\n\nMeaning: Whenever animals question the pigs\' privileges, Squealer invokes the threat of Jones returning.\n\nTechniques: Rhetorical question, fear-mongering, direct address ("comrades"), manipulation.\n\nThemes: Propaganda, fear, control, false binary.\n\nExam point: This is Squealer\'s most effective propaganda technique — the false binary. He presents only two options: accept the pigs\' rule or return to Jones. There is no third option (genuine equality). Orwell shows how authoritarian regimes maintain power by keeping the population more afraid of the alternative than of the current regime. Stalin used the same technique: accept Soviet rule or face capitalist exploitation.' },
      { id: 'af-q12', front: '"He had killed himself by drinking too much." (referring to Boxer\'s fate)', back: 'Speaker: Squealer\'s lie about Boxer (Chapter 9) — the narrator reveals the van said "Horse Slaughterer"\n\nMeaning: Squealer claims Boxer died peacefully in hospital. In reality, Napoleon sold him to the glue factory for whisky money.\n\nTechniques: Dramatic irony, euphemism, propaganda vs truth, pathos.\n\nThemes: Betrayal, exploitation, propaganda, cruelty of power.\n\nExam point: Boxer\'s death is the novel\'s most emotionally devastating moment. The most loyal, hardworking animal is sold for profit the moment he can no longer work. Orwell shows that totalitarian regimes see people as resources, not beings — useful until exhausted, then discarded. Benjamin (who reads the van\'s sign) represents those who see the truth but are powerless to act.' },

      // ── CHARACTER CARDS (8) ──
      { id: 'af-c1', front: 'Napoleon — Character Profile + Allegory', back: 'Allegorical parallel: Joseph Stalin\n\nRole: The pig who seizes power after the revolution, becoming a tyrannical dictator.\n\nKey traits: Cunning, ruthless, patient, strategic, uses others to do his bidding (Squealer for propaganda, dogs for enforcement).\n\nKey actions: Drives out Snowball using dogs; takes credit for the windmill; executes "traitors"; trades with humans; walks on two legs.\n\nOrwell\'s purpose: Napoleon demonstrates how revolutions are co-opted by those who seek power for its own sake. He never believed in equality — he trained the dogs in secret from the start. Like Stalin, he eliminates rivals, rewrites history, and uses terror to maintain control.\n\nExam tip: Napoleon rarely speaks publicly — he rules through Squealer (propaganda) and the dogs (force). This is Orwell\'s point: dictators don\'t need to be eloquent, just ruthless.' },
      { id: 'af-c2', front: 'Snowball — Character Profile + Allegory', back: 'Allegorical parallel: Leon Trotsky\n\nRole: The intelligent, idealistic pig who genuinely believes in Animalism but is expelled by Napoleon.\n\nKey traits: Eloquent, visionary, brave (leads the Battle of the Cowshed), believes in education and modernisation.\n\nKey actions: Writes the Seven Commandments; plans the windmill; is chased off the farm by Napoleon\'s dogs; becomes the scapegoat for everything that goes wrong.\n\nOrwell\'s purpose: Snowball represents the idealistic revolutionary who is destroyed by the pragmatic tyrant. Like Trotsky, he is exiled and then demonised — blamed for every failure despite being absent. Orwell shows how dictators need enemies, and if none exist, they invent them.\n\nExam tip: After Snowball\'s expulsion, Napoleon blames him for EVERYTHING — even destroying the windmill. This mirrors Stalin\'s propaganda against Trotsky.' },
      { id: 'af-c3', front: 'Boxer — Character Profile + Allegory', back: 'Allegorical parallel: The loyal Soviet working class (proletariat)\n\nRole: The cart-horse, the farm\'s hardest worker, who represents the exploited working class.\n\nKey traits: Immensely strong, loyal to a fault, unintelligent, trusting, defines himself through labour.\n\nKey actions: Works tirelessly on the windmill; adopts "Napoleon is always right"; is sold to the knacker when too old to work.\n\nOrwell\'s purpose: Boxer is the novel\'s tragic heart — his loyalty and strength should make him powerful, but his lack of education makes him vulnerable to exploitation. Orwell argues that the working class\'s greatest weakness is not lack of strength but lack of critical thinking. Without education, they cannot recognise when they are being used.\n\nExam tip: Boxer could overthrow Napoleon at any moment — he is the strongest animal. His refusal to do so shows that physical power without political awareness is meaningless.' },
      { id: 'af-c4', front: 'Squealer — Character Profile + Allegory', back: 'Allegorical parallel: Pravda (Soviet state media) / propaganda apparatus\n\nRole: Napoleon\'s spokesperson, responsible for manipulating the truth and maintaining the pigs\' legitimacy.\n\nKey traits: Eloquent, persuasive, nimble (literally and rhetorically), shameless liar, "could turn black into white."\n\nKey techniques: Statistics ("production has increased by 200%"), rhetorical questions ("You don\'t want Jones back?"), revision of commandments, emotional manipulation.\n\nOrwell\'s purpose: Squealer shows that propaganda is the ESSENTIAL tool of dictatorship — more important than force. He represents all state media that serves power rather than truth. Without Squealer, Napoleon could not maintain the illusion of legitimacy.\n\nExam tip: Squealer is caught repainting the commandments at night — this is Orwell\'s most literal image of history being rewritten by those in power.' },
      { id: 'af-c5', front: 'Old Major — Character Profile + Allegory', back: 'Allegorical parallel: Karl Marx / Vladimir Lenin (combined)\n\nRole: The elderly, respected boar whose speech inspires the revolution. He dies before it happens.\n\nKey traits: Wise, eloquent, idealistic, respected, visionary but naive about how his ideas will be applied.\n\nKey actions: Delivers the revolutionary speech; teaches "Beasts of England"; outlines the principles of Animalism; dies three days later.\n\nOrwell\'s purpose: Old Major represents the genuine idealism behind socialism/communism — his vision of equality is sincere. But Orwell shows that ideals are only as good as the people who implement them. Old Major\'s death before the revolution means he never sees his vision corrupted.\n\nExam tip: Old Major\'s ideas are not wrong — Orwell was a socialist himself. The tragedy is not the ideology but its corruption by Napoleon and Squealer.' },
      { id: 'af-c6', front: 'Benjamin the Donkey — Character Profile + Allegory', back: 'Allegorical parallel: Sceptical intellectuals / cynical observers who see the truth but do nothing\n\nRole: The oldest animal on the farm, cynical and literate, who sees through the pigs\' lies but refuses to act.\n\nKey traits: Intelligent, literate, pessimistic, passive, loyal only to Boxer.\n\nKey actions: Refuses to read the commandments for others; says "life would go on as it had always gone on — badly"; reads the van taking Boxer but too late to save him.\n\nOrwell\'s purpose: Benjamin represents the intelligentsia who see injustice but choose inaction. He knows the truth but his cynicism makes him complicit — silence in the face of tyranny enables it. Orwell criticises those who are smart enough to see oppression but too apathetic or afraid to resist.\n\nExam tip: Benjamin is arguably the most guilty character — he has the knowledge to expose the pigs but chooses silence. Orwell suggests that passive intelligence is as dangerous as active ignorance.' },
      { id: 'af-c7', front: 'The Dogs — Character Profile + Allegory', back: 'Allegorical parallel: The KGB / NKVD (Soviet secret police)\n\nRole: Napoleon\'s private army, trained from puppies to be his enforcers.\n\nKey traits: Violent, loyal only to Napoleon, feared by all animals, used to intimidate and execute.\n\nKey actions: Chase Snowball off the farm; guard Napoleon at all times; force confessions from "traitors"; enforce obedience through terror.\n\nOrwell\'s purpose: The dogs represent state violence — the force that backs up propaganda. Napoleon raised them in secret, showing that he planned his dictatorship from the beginning. Orwell demonstrates that every dictatorship requires both propaganda (Squealer) and force (the dogs) — one to convince, the other to compel.\n\nExam tip: The dogs were taken from their mothers as puppies — Napoleon corrupted them before they could develop independent thought. This mirrors how totalitarian states indoctrinate children.' },
      { id: 'af-c8', front: 'Mollie — Character Profile + Allegory', back: 'Allegorical parallel: The Russian bourgeoisie / middle class who fled to the West\n\nRole: The vain horse who cares more about sugar and ribbons than revolution.\n\nKey traits: Vain, superficial, self-interested, apolitical, ultimately disloyal to Animal Farm.\n\nKey actions: Asks if she can still wear ribbons after the revolution; is seen being petted by humans; eventually leaves the farm for a human household.\n\nOrwell\'s purpose: Mollie represents those who benefited from the old system and have no interest in equality — they just want comfort. She is not evil but self-absorbed, prioritising personal luxury over collective justice.\n\nExam tip: Mollie is a minor character but makes an important point — not everyone wants revolution, and some will always choose personal comfort over political principles. Orwell does not entirely condemn her; he shows that revolution demands sacrifices not everyone is willing to make.' },

      // ── THEME CARDS (8) ──
      { id: 'af-t1', front: 'Theme: Corruption of Power', back: 'Central idea: Power corrupts those who hold it, regardless of their original intentions.\n\nHow it\'s shown:\n- The pigs begin as equals and end as tyrants\n- The Seven Commandments are gradually rewritten\n- Napoleon moves into Jones\'s house, sleeps in his bed, drinks his whisky\n- The final image: pigs indistinguishable from humans\n\nOrwell\'s argument: The problem is not WHO holds power but WHAT power does to those who hold it. The revolution\'s failure is not accidental — it is inevitable because power corrupts. Orwell, a democratic socialist, supported equality but warned that any system concentrating power in a few hands will produce tyranny.\n\nExam tip: Orwell is NOT saying socialism is bad — he is saying that revolution without democratic safeguards will always be corrupted. The pigs\' corruption mirrors Stalin\'s, not socialism itself.' },
      { id: 'af-t2', front: 'Theme: Propaganda and the Manipulation of Language', back: 'Central idea: Those who control language control reality — propaganda is the most powerful weapon of dictatorship.\n\nHow it\'s shown:\n- Squealer rewrites the commandments\n- "Four legs good, two legs bad" → "Four legs good, two legs better"\n- Statistics are fabricated to prove production is increasing\n- "Beasts of England" is banned and replaced with a hymn to Napoleon\n- Snowball is rewritten from hero to villain\n\nOrwell\'s argument: Language is not a neutral tool — it is a weapon. When a regime controls language, it controls thought. Orwell later explored this idea in 1984 (Newspeak). In Animal Farm, the animals\' inability to read makes them vulnerable to the pigs\' revisions.\n\nExam tip: Every changed commandment demonstrates Orwell\'s thesis about language and power. Track the changes across the novel for a structured essay.' },
      { id: 'af-t3', front: 'Theme: Class and Inequality', back: 'Central idea: Revolution does not eliminate class — it merely creates a new ruling class.\n\nHow it\'s shown:\n- Under Jones: humans exploit animals\n- After revolution: pigs gradually become the new exploiters\n- Pigs take the milk and apples "for their health"\n- Pigs move into the farmhouse while others sleep in barns\n- Pigs walk on two legs and carry whips\n\nOrwell\'s argument: The structure of inequality survives revolution — only the personnel change. Orwell calls this "the endless cycle" — every revolution promises equality but produces a new elite. The working animals end up no better off than before.\n\nExam tip: The key structural point is that the end mirrors the beginning — Animal Farm under Napoleon is IDENTICAL to Manor Farm under Jones. Orwell uses cyclical structure to argue that revolution without genuine equality is meaningless.' },
      { id: 'af-t4', front: 'Theme: Education and Ignorance', back: 'Central idea: An uneducated population cannot protect itself from exploitation.\n\nHow it\'s shown:\n- Only the pigs learn to read fluently\n- Boxer can only learn four letters of the alphabet\n- The sheep mindlessly repeat slogans\n- The animals cannot verify if the commandments have changed\n- Benjamin CAN read but refuses to share knowledge\n\nOrwell\'s argument: Education is the foundation of freedom. The pigs maintain power BECAUSE the other animals cannot read, think critically, or remember the past accurately. Orwell argues that dictatorships depend on ignorance — an educated population would see through Squealer\'s lies.\n\nExam tip: The pigs\' first act of privilege is reserving milk and apples for themselves — the first sign that education (their literacy) is being used to exploit rather than liberate.' },
      { id: 'af-t5', front: 'Theme: Revolution and Betrayal', back: 'Central idea: Revolutions are idealistic in origin but are inevitably betrayed by those who seize power.\n\nHow it\'s shown:\n- Old Major\'s vision: genuine equality, no exploitation, all animals as comrades\n- The reality: Napoleon\'s dictatorship, executions, slave labour, trading with humans\n- The Seven Commandments: from principles to propaganda\n- The ending: pigs become humans\n\nOrwell\'s argument: Orwell supported the PRINCIPLES of socialism but witnessed their betrayal in the Soviet Union. Animal Farm argues that revolution fails not because equality is impossible but because power attracts the corruptible. Without mechanisms to prevent power concentration (democracy, free press, education), revolution will always produce new tyrants.\n\nExam tip: Orwell was a socialist critiquing Stalinism, NOT socialism. He believed in equality but warned against totalitarianism disguised as revolution.' },
      { id: 'af-t6', front: 'Theme: Fear and Control', back: 'Central idea: Totalitarian regimes maintain power through fear — both external threats and internal purges.\n\nHow it\'s shown:\n- "Surely you don\'t want Jones back?" — fear of the old regime\n- Napoleon\'s dogs — fear of violence\n- Public executions of "traitors" — fear of accusation\n- Snowball as scapegoat — fear of the enemy within\n\nOrwell\'s argument: Fear is the complement to propaganda — where propaganda fails to convince, fear compels obedience. Napoleon uses both: Squealer for the mind, the dogs for the body. The show trials (where animals confess to impossible crimes) mirror Stalin\'s Great Purge of the 1930s.\n\nExam tip: The confessions are the novel\'s most chilling moment — animals "confess" to crimes they didn\'t commit because fear overrides truth. This directly parallels the Moscow Show Trials.' },
      { id: 'af-t7', front: 'Theme: The Rewriting of History', back: 'Central idea: Those who control the past control the present — totalitarian regimes survive by rewriting history.\n\nHow it\'s shown:\n- The Seven Commandments are physically altered on the barn wall\n- Snowball\'s role in the Battle of the Cowshed is rewritten — from hero to traitor\n- Napoleon claims the windmill was HIS idea (it was Snowball\'s)\n- "Beasts of England" is banned and replaced\n- The animals\' memories become unreliable\n\nOrwell\'s argument: If you can change the record of what happened, you can change what people believe is happening NOW. The animals cannot resist because they cannot PROVE the past was different. Orwell later wrote: "Who controls the past controls the future. Who controls the present controls the past" (1984).\n\nExam tip: The barn wall is the novel\'s most important symbol — it is the animals\' constitution, and its alteration represents the corruption of law itself.' },
      { id: 'af-t8', front: 'Theme: Complicity and Silence', back: 'Central idea: Tyranny succeeds not just because of tyrants but because of those who allow it.\n\nHow it\'s shown:\n- Benjamin sees the truth but stays silent\n- The hens\' rebellion is the only resistance — and it is crushed\n- Clover suspects changes to the commandments but cannot read well enough to confirm\n- The sheep drown out dissent with chanting\n\nOrwell\'s argument: Every dictatorship requires the complicity of the majority — through fear, ignorance, or apathy. Orwell criticises not just Napoleon but the animals who allow his rise. Benjamin\'s silence, Boxer\'s blind loyalty, and the sheep\'s mindless repetition are all forms of complicity.\n\nExam tip: Orwell challenges the reader: which animal are YOU? The question forces self-reflection about how ordinary people enable tyranny through inaction.' },

      // ── ALLEGORY CARDS (7) ──
      { id: 'af-a1', front: 'Allegory: The Russian Revolution (1917)', back: 'Novel parallel: The animals\' rebellion against Mr Jones\n\nHistorical event: The Bolshevik Revolution overthrew Tsar Nicholas II, ending centuries of Russian monarchy.\n\nCorrespondences:\n- Mr Jones = Tsar Nicholas II (incompetent, neglectful ruler)\n- Old Major\'s speech = Marx\'s Communist Manifesto (inspiring revolutionary ideology)\n- The rebellion = October Revolution (1917)\n- "Beasts of England" = "The Internationale" (revolutionary anthem)\n- Animal Farm = The Soviet Union\n\nOrwell\'s point: The revolution began with genuine idealism — real grievances, real suffering, real desire for equality. Orwell does not mock the revolution itself but mourns its corruption. The tragedy is not that the animals rebelled but that their rebellion was stolen from them.' },
      { id: 'af-a2', front: 'Allegory: Stalin vs Trotsky', back: 'Novel parallel: Napoleon vs Snowball\n\nHistorical events:\n- Trotsky was Lenin\'s likely successor, an intellectual and military leader\n- Stalin outmanoeuvred Trotsky politically, expelled him (1929), then had him assassinated (1940)\n- Stalin rewrote Soviet history to erase Trotsky\'s contributions and paint him as a traitor\n\nCorrespondences:\n- Napoleon\'s dogs chase Snowball off the farm = Stalin exiling Trotsky\n- Snowball blamed for everything = Trotsky demonised as enemy of the state\n- Napoleon claims the windmill idea = Stalin taking credit for Trotsky\'s policies\n\nOrwell\'s point: The power struggle was never ideological — it was personal. Napoleon/Stalin did not defeat Snowball/Trotsky with better ideas but with better tactics: violence, propaganda, and ruthlessness.' },
      { id: 'af-a3', front: 'Allegory: The Great Purge (1936-38)', back: 'Novel parallel: Napoleon\'s executions of "traitor" animals\n\nHistorical events:\n- Stalin conducted mass purges, executing hundreds of thousands of Soviet citizens\n- Show trials: prominent Bolsheviks forced to confess to absurd crimes before execution\n- Anyone could be accused — paranoia consumed Soviet society\n\nCorrespondences:\n- Animals confessing to working with Snowball = Moscow Show Trials\n- Dogs executing confessed animals = NKVD/KGB executing "enemies of the people"\n- The atmosphere of terror = the Great Terror that paralysed Soviet society\n\nOrwell\'s point: The purges were not justice but theatre — designed to maintain fear and eliminate anyone who might challenge Napoleon. The confessions are meaningless (the animals confess to impossible crimes), but the executions are real. Fear, not truth, is the point.' },
      { id: 'af-a4', front: 'Allegory: The Windmill = Soviet Industrialisation', back: 'Novel parallel: The building, destruction, and rebuilding of the windmill\n\nHistorical events:\n- Stalin\'s Five-Year Plans (1928-1932+) aimed to rapidly industrialise the USSR\n- Workers suffered terrible conditions: long hours, low rations, harsh punishments\n- Stalin claimed industrial miracles while workers starved\n\nCorrespondences:\n- The windmill = Soviet industrialisation / Five-Year Plans\n- Animals\' exhausting labour = forced labour of Soviet workers\n- Windmill destroyed by storm (blamed on Snowball) = industrial failures blamed on saboteurs and Trotsky\n- Napoleon claims windmill is a success = Stalin\'s propaganda about industrial achievement\n\nOrwell\'s point: Industrialisation was supposed to benefit everyone but only benefited the ruling class. The animals build the windmill but the pigs enjoy the profits — exactly as Soviet workers built industry that enriched the Party elite.' },
      { id: 'af-a5', front: 'Allegory: The Battle of the Cowshed = Civil War / Foreign Intervention', back: 'Novel parallel: Jones and neighbouring farmers attack Animal Farm; the animals defend it\n\nHistorical events:\n- After the 1917 Revolution, the Russian Civil War (1917-1922) saw "White" forces (supported by Western nations) try to destroy the Bolshevik government\n- The Red Army, led partly by Trotsky, successfully defended the revolution\n\nCorrespondences:\n- Jones\'s attack = counter-revolutionary forces\n- Snowball\'s bravery = Trotsky\'s military leadership of the Red Army\n- "Animal Hero, First Class" = Soviet military medals\n- Later rewriting of Snowball\'s role = Stalin erasing Trotsky\'s military achievements\n\nOrwell\'s point: Snowball/Trotsky genuinely defended the revolution — but Napoleon/Stalin later rewrote history to claim the credit and paint the real hero as a traitor.' },
      { id: 'af-a6', front: 'Allegory: Napoleon\'s Trade with Humans = Soviet-Western Relations', back: 'Novel parallel: Napoleon begins trading with neighbouring farms through Mr Whymper\n\nHistorical events:\n- Stalin signed trade deals with capitalist nations despite communist ideology\n- The Nazi-Soviet Pact (1939) — Stalin allied with Hitler, shocking the world\n- At Tehran (1943), Stalin sat with Churchill and Roosevelt as equals\n\nCorrespondences:\n- Mr Whymper (solicitor/middleman) = Western businessmen and diplomats\n- Trading with Pilkington and Frederick = alliances with Britain/USA and Germany\n- The card game at the end = the Tehran Conference (Allied leaders dividing the post-war world)\n- The quarrel over cheating = the inevitable breakdown of the wartime alliance (Cold War)\n\nOrwell\'s point: The pigs\' willingness to trade with the very humans they overthrew proves the revolution is dead. Ideology has been replaced by pragmatic self-interest — exactly as Stalin abandoned communist principles when it suited him.' },
      { id: 'af-a7', front: 'Allegory: Mr Jones = Tsar Nicholas II / The Old Regime', back: 'Novel parallel: Mr Jones is the farm\'s negligent, drunken owner who is overthrown\n\nHistorical figure: Tsar Nicholas II — the last Emperor of Russia\n\nCorrespondences:\n- Jones neglects the animals (forgets to feed them) = Nicholas II ignored the suffering of the Russian people\n- Jones is drunk and incompetent = Nicholas was weak, out of touch, and poorly advised\n- Jones is overthrown when animals snap = Nicholas abdicated during the February Revolution (1917)\n- Jones tries to retake the farm = counter-revolutionary "White" forces in the Civil War\n- The threat of Jones\'s return is used to justify the pigs\' rule = Soviet propaganda about the return of capitalism\n\nOrwell\'s point: Jones is not a cartoon villain — he is simply negligent and selfish. Orwell suggests that tyranny often begins not with active cruelty but with the ruling class\'s indifference to suffering. The revolution was justified; its hijacking was the crime.' },
    ],
  },
];
